<script>
    import * as d3 from 'd3';
    import {legendColor} from 'd3-svg-legend';

    export let data;
    export let fullData;
    export let varConfig;
    export let selectedVar = 'surv_self';
    export let selectedPoints = [];

    let width = 800;
    let height = 400;

    let proj = d3.geoMercator()
        .scale(75)
        .center([0, 60])  
        .translate([width / 2, height / 2]);
    let path = d3.geoPath().projection(proj);

    $: selectedSet = new Set(
        (selectedPoints || []).map(d => d.properties.country)
    );

    $: scale = d3.scaleSequential(varConfig[selectedVar].color)
        .domain(varConfig[selectedVar].domain);

    let legend;
    $: {	
            const colorLegend = legendColor()
                .shape('rect')
                .cells(11)
                .scale(scale);

            d3.select(legend)
                .call(colorLegend);
        }

</script>

<main>
    <svg {width} {height}>
        {#each data as d}
        <path
            d={path(d)}
            fill={
                !isNaN(+d.properties[selectedVar])
                    ? (selectedSet.size === 0 || selectedSet.has(d.properties.country)
                    ? scale(+d.properties[selectedVar])
                    : "#eee"): "#fff"
                }
            stroke="white"
        />
        {/each}
        {#each fullData as d}
          <path class = "geooverlay"
            d={path(d)}/>
        {/each}

        <g transform="translate({width - 100}, 50)"
              bind:this={legend} />
      </svg>
</main>

<style>
    .geooverlay {
      stroke: grey;
      stroke-width: 1px;
      fill: none;
    }
